#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int cmp_desc(const void *a, const void *b) {
    int x = *(int*)b - *(int*)a;
    return x;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char *s = (char*)malloc(N+5);
        scanf("%s", s);
        // vectors for 26 letters
        int *seg[26];
        int segCnt[26];
        for(int i=0;i<26;i++){ seg[i]=NULL; segCnt[i]=0; }
        int i=0;
        while(i<N){
            char c = s[i];
            int j=i;
            while(j<N && s[j]==c) j++;
            int len = j-i;
            int idx = c-'a';
            seg[idx] = (int*)realloc(seg[idx], (segCnt[idx]+1)*sizeof(int));
            seg[idx][segCnt[idx]++] = len;
            i=j;
        }
        // answer array
        int *ans = (int*)calloc(N+1, sizeof(int));
        for(int ch=0; ch<26; ++ch){
            if(segCnt[ch]==0) continue;
            qsort(seg[ch], segCnt[ch], sizeof(int), cmp_desc);
            int pref = 0;
            for(int t=1; t<=segCnt[ch]; ++t){
                pref += seg[ch][t-1];
                int k = t-1; // need t-1 reversals
                if(pref > ans[k]) ans[k] = pref;
            }
        }
        // make non‑decreasing
        for(int k=1;k<=N;k++) if(ans[k] < ans[k-1]) ans[k] = ans[k-1];
        // output
        for(int k=0;k<=N;k++){
            if(k) printf(" ");
            printf("%d", ans[k]);
        }
        printf("\n");
        // free
        for(int ch=0; ch<26; ++ch) free(seg[ch]);
        free(ans); free(s);
    }
    return 0;
}

