    while(T--){
        int N; cin>>N; string s; cin>>s;
        vector<vector<int>> seg(26);
        for(int i=0;i<N;){
            char c=s[i];
            int j=i;
            while(j<N && s[j]==c) ++j;
            seg[c-'a'].push_back(j-i);
            i=j;
        }
        vector<int> ans(N+1,0);
        for(int ch=0; ch<26; ++ch){
            auto &v=seg[ch];
            if(v.empty()) continue;
            sort(v.begin(), v.end(), greater<int>());
            int pref=0;
            for(int t=1; t<= (int)v.size(); ++t){
                pref+=v[t-1];
                int k=t-1;
                ans[k]=max(ans[k], pref);
            }
        }
        for(int k=1;k<=N;++k) ans[k]=max(ans[k], ans[k-1]);
        for(int k=0;k<=N;++k){
            if(k) cout<<' ';
            cout<<ans[k];
        }
        cout<<'\n';
    }
    return 0;
}

