import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            char[] s = fs.next().toCharArray();
            @SuppressWarnings("unchecked")
            ArrayList<Integer>[] seg = new ArrayList[26];
            for (int i = 0; i < 26; i++) seg[i] = new ArrayList<>();
            for (int i = 0; i < N; ) {
                char c = s[i];
                int j = i;
                while (j < N && s[j] == c) j++;
                seg[c - 'a'].add(j - i);
                i = j;
            }
            int[] ans = new int[N + 1];
            for (int ch = 0; ch < 26; ch++) {
                List<Integer> list = seg[ch];
                if (list.isEmpty()) continue;
                list.sort(Collections.reverseOrder());
                int pref = 0;
                for (int t = 1; t <= list.size(); t++) {
                    pref += list.get(t - 1);
                    int k = t - 1;
                    if (pref > ans[k]) ans[k] = pref;
                }
            }
            for (int k = 1; k <= N; k++) ans[k] = Math.max(ans[k], ans[k - 1]);
            for (int k = 0; k <= N; k++) {
                if (k > 0) out.append(' ');
                out.append(ans[k]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for Java
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
    }
}

