import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it).strip()
        seg = [[] for _ in range(26)]
        i = 0
        while i < N:
            c = s[i]
            j = i
            while j < N and s[j] == c:
                j += 1
            seg[ord(c) - 97].append(j - i)
            i = j
        ans = [0] * (N + 1)
        for lst in seg:
            if not lst:
                continue
            lst.sort(reverse=True)
            pref = 0
            for t, val in enumerate(lst, start=1):
                pref += val
                k = t - 1
                if pref > ans[k]:
                    ans[k] = pref
        for k in range(1, N + 1):
            if ans[k] < ans[k - 1]:
                ans[k] = ans[k - 1]
        out_lines.append(' '.join(map(str, ans)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

