let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let tc = 0; tc < T; ++tc) {
  const N = Number(input[idx++]);
  const s = input[idx++];
  const seg = Array.from({ length: 26 }, () => []);
  let i = 0;
  while (i < N) {
    const ch = s.charCodeAt(i) - 97;
    let j = i;
    while (j < N && s.charCodeAt(j) - 97 === ch) ++j;
    seg[ch].push(j - i);
    i = j;
  }
  const ans = new Array(N + 1).fill(0);
  for (let ch = 0; ch < 26; ++ch) {
    const arr = seg[ch];
    if (arr.length === 0) continue;
    arr.sort((a, b) => b - a);
    let pref = 0;
    for (let t = 1; t <= arr.length; ++t) {
      pref += arr[t - 1];
      const k = t - 1;
      if (pref > ans[k]) ans[k] = pref;
    }
  }
  for (let k = 1; k <= N; ++k) if (ans[k] < ans[k - 1]) ans[k] = ans[k - 1];
  outputs.push(ans.join(' '));
}
